// Tool – AI RSS Labs & Tech
// This node runs AFTER "Merge" and prepares clean, filtered RSS items
// for the AI Agent.
//
// It does three things:
// 1) Reads the date passed from the orchestrator via the trigger
// 2) Takes all merged RSS items from the previous node
// 3) Filters to that date, normalizes fields, removes errors & duplicates

// 1) Try to get the target date from the trigger
let targetDate = '';

try {
  const triggerItems = $items('When Executed by Another Workflow') || [];
  if (triggerItems.length > 0 && triggerItems[0].json) {
    const t = triggerItems[0].json;
    // Call n8n Workflow Tool usually passes { input: "YYYY-MM-DD" }
    targetDate = t.input || t.targetDate || '';
  }
} catch (e) {
  // If the trigger isn't available (e.g. manual node execution),
  // we just leave targetDate empty and skip date filtering.
  targetDate = '';
}

// 2) Get all merged RSS entries from the previous node
// (the node connected directly before this Code node)
const mergedItems = $items(); // items from "Merge"

// 3) Normalize & filter
const MAX_ITEMS = 20;
const seen = new Set();
const normalized = [];

for (const item of mergedItems) {
  const entry = item.json || {};

  // Skip error placeholders like { error: "Status code 404" }
  if (entry.error) continue;

  const rawDate =
    entry.isoDate ||
    entry.pubDate ||
    entry.pubdate ||
    entry.published ||
    '';

  const dateOnly = rawDate.slice(0, 10); // "YYYY-MM-DD"

  // If we have a targetDate, keep only items from that date
  if (targetDate && dateOnly !== targetDate) {
    continue;
  }

  const title = entry.title || '';
  const url = entry.link || entry.guid || '';
  const source =
    entry.feedTitle ||
    entry.creator ||
    entry.source ||
    'RSS Labs & Tech';

  if (!title || !url) continue;

  // Simple de-duplication by title+url
  const dedupeKey = `${title}::${url}`;
  if (seen.has(dedupeKey)) continue;
  seen.add(dedupeKey);

  normalized.push({
    title,
    url,
    source,
    publishedAt: rawDate || null,
    snippet: entry.contentSnippet || entry.summary || '',
  });

  if (normalized.length >= MAX_ITEMS) break;
}

// 4) Return in the shape the AI Agent expects
return normalized.map(obj => ({ json: obj }));
